arguments.file_text:
@* Step progress indicator with clickable completed steps *@

<nav class="mb-4">
    <div class="d-flex align-items-start">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i + 1;
            var name = StepNames[i];
            var isCurrent = step == CurrentStep;
            var isCompleted = CompletedSteps.Contains(step) && !isCurrent;
            var isClickable = CompletedSteps.Contains(step) && !isCurrent;

            @if (i > 0)
            {
                <div class="flex-fill align-self-center"
                     style="height: 2px; background: @(isCompleted || isCurrent ? "#0d6efd" : "#dee2e6"); margin-top: -10px;">
                </div>
            }

            <div class="text-center" style="min-width: 80px; cursor: @(isClickable ? "pointer" : "default")"
                 @onclick="() => HandleClick(step)">
                <div class="rounded-circle d-flex align-items-center justify-content-center mx-auto mb-1 @CircleClass(isCurrent, isCompleted)"
                     style="width: 36px; height: 36px; font-size: 0.85rem;">
                    @if (isCompleted)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <small class="d-none d-sm-block @LabelClass(isCurrent, isCompleted)" style="font-size: 0.75rem;">@name</small>
            </div>
        }
    </div>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public List<string> StepNames { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleClick(int step)
    {
        if (CompletedSteps.Contains(step) && step != CurrentStep)
            await OnStepClicked.InvokeAsync(step);
    }

    private static string CircleClass(bool isCurrent, bool isCompleted) =>
        isCurrent ? "bg-primary text-white"
        : isCompleted ? "bg-success text-white"
        : "bg-light text-muted border";

    private static string LabelClass(bool isCurrent, bool isCompleted) =>
        isCurrent ? "fw-bold text-primary"
        : isCompleted ? "text-success"
        : "text-muted";
}

@using sv_0472d1e025084ab188be4f542dc514ef.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company <span class="text-danger">*</span></label>
                <input class="form-control @FieldClass("Company")" @bind="Entry.Company" @bind:event="oninput" />
                @if (Errors.ContainsKey("Company"))
                {
                    <div class="invalid-feedback d-block">@Errors["Company"]</div>
                }
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input class="form-control @FieldClass("Title")" @bind="Entry.Title" @bind:event="oninput" />
                @if (Errors.ContainsKey("Title"))
                {
                    <div class="invalid-feedback d-block">@Errors["Title"]</div>
                }
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control @FieldClass("StartDate")" @bind="Entry.StartDate" />
                @if (Errors.ContainsKey("StartDate"))
                {
                    <div class="invalid-feedback d-block">@Errors["StartDate"]</div>
                }
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" @bind="Entry.EndDate" disabled="@Entry.IsCurrent" />
