{"file_text": "<div>
    <h4 class="mb-3">Cover Letter</h4>

    <div class="mb-3">
        <textarea class="form-control" rows="12"
                  value="@Text"
                  @oninput="HandleInput"
                  maxlength="@MaxLength"
                  placeholder="Write your cover letter here..."></textarea>
        <div class="text-muted small mt-1 text-end">
            @(Text?.Length ?? 0) / @MaxLength characters
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string Text { get; set; } = "";
    [Parameter] public EventCallback<string> TextChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        if (value.Length <= MaxLength)
            await TextChanged.InvokeAsync(value);
    }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync();
    }
}
