@page "/apply"
@rendermode InteractiveServer
@using sv_0472d1e025084ab188be4f542dc514ef.Models
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 780px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   StepNames="stepNames"
                   OnStepClicked="GoToStep" />

    @if (applicationId.HasValue)
    {
        <div class="alert alert-success text-center py-5">
            <h3 class="mb-3">✓ Application Submitted</h3>
            <p class="lead">Your application ID is <strong>#@applicationId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="personalInfo"
                                  EmailError="@emailError"
                                  IsValidating="isValidatingEmail"
                                  OnNext="HandlePersonalInfoNext" />
                break;
            case 2:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="HandleStepComplete(2)"
                                 OnBack="PreviousStep" />
                break;
            case 3:
                <ReferencesStep References="references"
                                OnNext="HandleStepComplete(3)"
                                OnBack="PreviousStep" />
                break;
            case 4:
                <CoverLetterStep @bind-Text="coverLetter"
                                 OnNext="HandleStepComplete(4)"
                                 OnBack="PreviousStep" />
                break;
            case 5:
                <ReviewStep PersonalInfo="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            IsSubmitting="isSubmitting"
                            OnEditStep="GoToStep"
                            OnSubmit="HandleSubmit"
                            OnBack="PreviousStep" />
                break;
        }
    }
</div>

@code {
    private int currentStep = 1;
    private readonly HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new() };
    private List<ReferenceModel> references = new() { new(), new() };
    private string coverLetter = "";

    private bool isValidatingEmail;
    private bool isSubmitting;
    private int? applicationId;
    private string? emailError;

    private readonly List<string> stepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }

    private void PreviousStep()
    {
        if (currentStep > 1)
            currentStep--;
    }

    private EventCallback HandleStepComplete(int step)
    {
        return EventCallback.Factory.Create(this, () =>
        {
            completedSteps.Add(step);
            currentStep = step + 1;
        });
    }

    private async Task HandlePersonalInfoNext()
    {
        emailError = null;
        isValidatingEmail = true;

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(personalInfo.Email);
            if (!isValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }

            completedSteps.Add(1);
            currentStep = 2;
        }
        finally
        {
            isValidatingEmail = false;
        }
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;

        try
        {
            var application = new JobApplication(
                new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
                new WorkHistory(workEntries.Select(e => new WorkEntry(
                    e.Company,
                    e.Title,
                    e.StartDate ?? DateTime.Today,
                    e.IsCurrent ? null : e.EndDate,
                    e.Description
                )).ToList()),
                references
                    .Where(r => !string.IsNullOrWhiteSpace(r.Name))
                    .Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone))
                    .ToList(),
                coverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            completedSteps.Add(5);
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

