+            if (!isValid)
+            {
+                emailError = "Please enter a valid email address.";
+                return;
+            }
+
+            completedSteps.Add(1);
+            currentStep = 2;
+        }
+        finally
+        {
+            isValidatingEmail = false;
+        }
+    }
+
+    private async Task HandleSubmit()
+    {
+        isSubmitting = true;
+
+        try
+        {
+            var application = new JobApplication(
+                new PersonalInfo(personalInfo.FullName, personalInfo.Email, personalInfo.Phone, personalInfo.Address),
+                new WorkHistory(workEntries.Select(e => new WorkEntry(
+                    e.Company,
+                    e.Title,
+                    e.StartDate ?? DateTime.Today,
+                    e.IsCurrent ? null : e.EndDate,
+                    e.Description
+                )).ToList()),
+                references
+                    .Where(r => !string.IsNullOrWhiteSpace(r.Name))
+                    .Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone))
+                    .ToList(),
+                coverLetter
+            );
+
+            applicationId = await ApplicationService.SubmitApplicationAsync(application);
+            completedSteps.Add(5);
+        }
+        finally
+        {
+            isSubmitting = false;
+        }
+    }
+}
